def create_tar_gz(source_dir, output_path, exclude_patterns=None):
    """Create a tar.gz compressed archive."""
    logger.info("Creating tar.gz archive: %s", output_path)
    try:
        with tarfile.open(output_path, 'w:gz') as tar:
            base_name = os.path.basename(source_dir.rstrip(os.sep))
            for root, dirs, files in os.walk(source_dir):
                # Filter excluded patterns
                if exclude_patterns:
                    dirs[:] = [d for d in dirs if not _matches_pattern(d, exclude_patterns)]

                for f in files:
                    if exclude_patterns and _matches_pattern(f, exclude_patterns):
                        continue
                    full_path = os.path.join(root, f)
                    rel_path = os.path.relpath(full_path, os.path.dirname(source_dir))
                    try:
                        tar.add(full_path, arcname=rel_path)
                    except (OSError, IOError) as e:
                        logger.warning("Could not add file %s: %s", full_path, str(e))
                    except tarfile.TarError as e:
                        logger.warning("Tar error for %s: %s", full_path, str(e))

                # Also add empty directories
                for d in dirs:
                    full_path = os.path.join(root, d)
                    rel_path = os.path.relpath(full_path, os.path.dirname(source_dir))
                    try:
                        tar.add(full_path, arcname=rel_path, recursive=False)
                    except (OSError, IOError, tarfile.TarError):
                        pass

        return True
    except Exception as e:
        logger.error("Failed to create tar.gz archive: %s", str(e))
        return False


