def create_zip(source_dir, output_path, exclude_patterns=None):
    """Create a zip compressed archive."""
    logger.info("Creating zip archive: %s", output_path)
    try:
        # Use ZIP_DEFLATED if available, fall back to ZIP_STORED
        try:
            import zlib
            compression = zipfile.ZIP_DEFLATED
        except ImportError:
            logger.warning("zlib not available, using ZIP_STORED (no compression)")
            compression = zipfile.ZIP_STORED

        with zipfile.ZipFile(output_path, 'w', compression, allowZip64=True) as zf:
            for root, dirs, files in os.walk(source_dir):
                if exclude_patterns:
                    dirs[:] = [d for d in dirs if not _matches_pattern(d, exclude_patterns)]

                for f in files:
                    if exclude_patterns and _matches_pattern(f, exclude_patterns):
                        continue
                    full_path = os.path.join(root, f)
                    rel_path = os.path.relpath(full_path, os.path.dirname(source_dir))
                    try:
                        zf.write(full_path, rel_path)
                    except (OSError, IOError) as e:
                        logger.warning("Could not add file %s: %s", full_path, str(e))

        return True
    except Exception as e:
        logger.error("Failed to create zip archive: %s", str(e))
        return False


